71	// ─── Tool deadline wrapper ────────────────────────────────────────────────────
72	
73	type ToolResult = { content: { type: "text"; text: string }[] };
74	
75	async function withToolDeadline(toolName: string, fn: () => Promise<ToolResult>): Promise<ToolResult> {
76	  let timer: ReturnType<typeof setTimeout>;
77	  const deadline = new Promise<ToolResult>((resolve) => {
78	    timer = setTimeout(() => {
79	      console.warn(`[nas-mcp] Tool "${toolName}" deadline reached after ${TOOL_DEADLINE_MS}ms`);
80	      resolve({
81	        content: [{
82	          type: "text" as const,
83	          text: `Tool "${toolName}" timed out after ${TOOL_DEADLINE_MS / 1000}s. The NAS may be under heavy load or unreachable. Try again in a moment, or target a single NAS instead of "both".`,
84	        }],
85	      });
86	    }, TOOL_DEADLINE_MS);
87	  });
88	  try {
89	    return await Promise.race([fn(), deadline]);
90	  } finally {
91	    clearTimeout(timer!);
92	  }
93	}
94	
95	async function executePredefinedToolOnNas(
96	  tool: McpToolDef,
97	  input: Record<string, unknown>,
98	  config: ReturnType<typeof getNasConfigs>[number],
99	): Promise<string> {
100	  let command: string;
101	  try {
102	    command = tool.buildCommand(input);
103	  } catch (err) {
104	    return `[${config.name}] Cannot build command: ${err instanceof Error ? err.message : String(err)}`;
105	  }
106	
107	  try {
108	    if (!tool.write) {
109	      const result = await nasExec(config, command, 1);
110	      const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
111	      return `[${config.name}]\n${output || "(no output)"}`;
112	    }
113	
114	    const preview = await nasPreview(config, command);
115	
116	    if (preview.blocked) {
117	      return `[${config.name}] Blocked by NAS API: ${preview.summary}`;
118	    }
119	
120	    if (preview.tier >= 2 && !input.confirmed) {
121	      return [
122	        `[${config.name}] This action requires your approval before it runs.`,
123	        ``,
124	        `Command that will execute:`,
125	        `\`\`\``,
126	        command,
127	        `\`\`\``,
128	        ``,
129	        `Call this tool again with confirmed: true to approve and execute.`,
130	        `If you do not want to proceed, do nothing — no changes have been made.`,
131	      ].join("\n");
132	    }
133	
134	    let approvalToken: string | undefined;
135	    if (preview.tier >= 2) {
136	      approvalToken = buildApprovalToken(config, command, preview.tier);
137	    }
138	
139	    const result = await nasExec(config, command, preview.tier, approvalToken);
140	    const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
141	    return `[${config.name}]\n${output || "(no output)"}`;
142	  } catch (err) {
143	    return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
144	  }
145	}
146	
147	/**
148	 * Runs a predefined tool against the requested target NAS(es), returning the
149	 * combined text result. Shared between eager registration and invoke_tool.
150	 */
151	async function runPredefinedTool(
152	  tool: McpToolDef,
153	  input: Record<string, unknown>,
154	): Promise<ToolResult> {
155	  const target = (input.target as string) ?? "both";
156	  const configs = getNasConfigs(target);
157	  if (configs.length === 0) {
158	    return {
159	      content: [{ type: "text" as const, text: `No NAS configured for target "${target}". Valid targets: edgesynology1, edgesynology2, both.` }],
160	    };
161	  }
162	  const results = await Promise.all(configs.map((config) => executePredefinedToolOnNas(tool, input, config)));
163	  return {
164	    content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
165	  };
166	}
