192	// ─── MCP server factory ───────────────────────────────────────────────────────
193	
194	function createMcpServer(): McpServer {
195	  const server = new McpServer(
196	    { name: "synology-nas", version: "1.0.0" },
197	    { instructions: MCP_INSTRUCTIONS },
198	  );
199	
200	  // ── Always-on tool 1: tool_search ─────────────────────────────────────────
201	  server.tool(
202	    "tool_search",
203	    "Search the NAS diagnostic + admin tool registry by keyword. Call this FIRST to find the right tool for the task, then call invoke_tool to execute. Returns tool names, descriptions, and parameter shapes as text. Try keywords like: snapshot, backup, drive, sync, disk, smart, btrfs, network, tailscale, memory, cpu, logs, package, restart, files, permission, acl, recover, recycle, security, audit, volume, space, task. Group names also work: system, performance, network, security, drive_sync, logs, storage, files, recovery, packages, backup, write_restart, write_storage, write_files, write_tasks, misc.",
204	    {
205	      query: z.string().describe("Keywords describing what you want to do, e.g. 'snapshot recovery', 'sharesync errors', 'restart drive package'."),
206	      limit: z.number().int().optional().default(8).describe("Max tools to return. Default 8, max 30."),
207	    },
208	    async ({ query, limit }: { query: string; limit?: number }) => {
209	      return withToolDeadline("tool_search", async () => {
210	        const matches = searchTools(query, allEnabled);
211	        if (matches.length === 0) {
212	          return {
213	            content: [{
214	              type: "text" as const,
215	              text: `No tools matched "${query}". Try broader keywords (e.g. snapshot, drive, disk, network, files, logs, restart) or a group name (system, performance, network, security, drive_sync, logs, storage, files, recovery, packages, backup, write_restart, write_storage, write_files, write_tasks).`,
216	            }],
217	          };
218	        }
219	        const cap = Math.max(1, Math.min(limit ?? 8, 30));
220	        const top = matches.slice(0, cap);
221	        const body = top.map(formatToolForSearch).join("\n\n");
222	        const more = matches.length > top.length
223	          ? `\n\n(${matches.length - top.length} additional match(es) not shown — refine the query or raise limit.)`
224	          : "";
225	        const header = `Found ${matches.length} tool(s) for "${query}". Showing top ${top.length}.\nExecute any of these with: invoke_tool({ name: "<tool>", target: "edgesynology1|edgesynology2|both", args: { ... } })\n\n`;
226	        return { content: [{ type: "text" as const, text: header + body + more }] };
227	      });
228	    },
229	  );
230	
231	  // ── Always-on tool 2: invoke_tool ─────────────────────────────────────────
232	  server.tool(
233	    "invoke_tool",
234	    "Execute a NAS tool discovered via tool_search. Pass the tool's exact name, the target NAS, and any tool-specific params in args. For write tools, include confirmed: true inside args to actually run (omit it first to see a preview). Returns the tool's output as text.",
235	    {
236	      name: z.string().describe("Exact tool name from tool_search output."),
237	      target: z
238	        .enum(["edgesynology1", "edgesynology2", "both"])
239	        .describe("Which NAS to run on."),
240	      args: z
241	        .record(z.unknown())
242	        .optional()
243	        .describe("Tool-specific parameters from the tool_search schema. For write tools, include confirmed: true to execute."),
244	    },
245	    async ({ name, target, args }: { name: string; target: string; args?: Record<string, unknown> }) => {
246	      return withToolDeadline(`invoke_tool:${name}`, async () => {
247	        const tool = findToolByName(name);
248	        if (!tool) {
249	          return {
250	            content: [{
251	              type: "text" as const,
252	              text: `Unknown tool: "${name}". Call tool_search first to discover available tools.`,
253	            }],
254	          };
255	        }
256	        const isEnabled = tool.write ? enabledWrite.has(name) : enabledRead.has(name);
257	        if (!isEnabled) {
258	          return {
259	            content: [{
260	              type: "text" as const,
261	              text: `Tool "${name}" exists but is disabled in tools-config.json (${tool.write ? "enabled_write_tools" : "enabled_read_tools"}). Group: ${getGroup(name)}.`,
262	            }],
263	          };
264	        }
265	        const input: Record<string, unknown> = { ...(args ?? {}), target };
266	        return runPredefinedTool(tool, input);
267	      });
268	    },
269	  );
270	
271	  // ── Always-on tool 3: run_command (free-form, tier-1-only) ────────────────
272	  if (enabledRead.has("run_command")) {
273	    server.tool(
274	      "run_command",
275	      "Run any read-only shell command on a Synology NAS for deep diagnosis. Write commands are automatically blocked by the NAS API validator before execution. A small set of commands is permanently hard-blocked regardless of how many you have run (e.g. recursive grep over @synologydrive/@SynologyDriveShareSync — grep a specific log file instead); a block is a stateless rule on the command pattern, never a rate limit or session limit, so retrying or reconnecting will not change it.",
276	      {
277	        target: z
278	          .enum(["edgesynology1", "edgesynology2", "both"])
279	          .describe("Which NAS to run on"),
280	        command: z.string().describe("The shell command to execute"),
281	      },
282	      async ({ target, command }: { target: string; command: string }) => {
283	        return withToolDeadline("run_command", async () => {
284	          const configs = getNasConfigs(target);
285	          if (configs.length === 0) {
286	            return {
287	              content: [{ type: "text" as const, text: `No NAS configured for target "${target}".` }],
288	            };
289	          }
290	          const results = await Promise.all(
291	            configs.map(async (config) => {
292	              try {
293	                const preview = await nasPreview(config, command);
294	                if (preview.blocked) {
295	                  return `[${config.name}] Blocked: ${preview.summary}`;
296	                }
297	                if (preview.tier >= 2) {
298	                  return `[${config.name}] This command requires write access and cannot be run via run_command. Add it to enabled_write_tools in tools-config.json, or use invoke_tool with a specific write tool.`;
299	                }
300	                const result = await nasExec(config, command, 1);
301	                const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
302	                return `[${config.name}]\n${output || "(no output)"}`;
303	              } catch (err) {
304	                return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
305	              }
306	            }),
307	          );
308	          return {
309	            content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
310	          };
311	        });
312	      },
313	    );
314	  }
315	
316	  // ── Eager freebies: check_disk_space + restart_nas_api ────────────────────
317	  // Common enough that paying tool_search round-trip for them isn't worth it.
318	  for (const eagerName of EAGER_TOOLS) {
319	    const tool = ALL_TOOL_DEFS.find((t) => t.name === eagerName);
320	    if (!tool) continue;
321	    const isEnabled = tool.write ? enabledWrite.has(tool.name) : enabledRead.has(tool.name);
322	    if (!isEnabled) continue;
323	    registerToolDef(server, tool);
324	  }
325	
326	  return server;
327	}
