1	import { createHmac } from "node:crypto";
2	import { request as httpRequest } from "node:http";
3	import { request as httpsRequest } from "node:https";
4	
5	export interface NasConfig {
6	  name: string;
7	  url: string;
8	  apiSecret: string;
9	  approvalSigningKey: string;
10	}
11	
12	export interface NasPreviewResult {
13	  tier: number;
14	  summary: string;
15	  blocked: boolean;
16	}
17	
18	export interface NasExecResult {
19	  stdout: string;
20	  stderr: string;
21	  exit_code: number;
22	  timed_out?: boolean;
23	}
24	
25	// Hard cap on exec timeout sent to nas-api. Callers can request less but never more.
26	const MAX_EXEC_TIMEOUT_MS = 25_000;
27	const PREVIEW_TIMEOUT_MS = 8_000;
28	const MAX_RESPONSE_BYTES = 512 * 1024;
29	
30	function normalizeRequestError(err: unknown, label: string, timeoutMs: number): Error {
31	  if (err instanceof Error) {
32	    if (err.message.includes("__NAS_TIMEOUT__")) {
33	      return new Error(`${label} timed out after ${timeoutMs}ms — NAS may be under load`);
34	    }
35	    return err;
36	  }
37	  return new Error(`${label} failed: ${String(err)}`);
38	}
39	
40	async function requestJson<T>(
41	  config: NasConfig,
42	  path: string,
43	  body: Record<string, unknown>,
44	  timeoutMs: number,
45	  label: string,
46	): Promise<T> {
47	  const url = new URL(path, config.url);
48	  const payload = JSON.stringify(body);
49	  const requestImpl = url.protocol === "https:" ? httpsRequest : httpRequest;
50	
51	  return new Promise<T>((resolve, reject) => {
52	    const req = requestImpl(
53	      url,
54	      {
55	        method: "POST",
56	        agent: false,
57	        headers: {
58	          "Content-Type": "application/json",
59	          "Content-Length": Buffer.byteLength(payload),
60	          Authorization: `Bearer ${config.apiSecret}`,
61	          Connection: "close",
62	        },
63	      },
64	      (res) => {
65	        res.setEncoding("utf8");
66	
67	        let raw = "";
68	        res.on("data", (chunk: string) => {
69	          raw += chunk;
70	          if (raw.length > MAX_RESPONSE_BYTES) {
71	            res.destroy(new Error(`${label} failed (${config.name}): response exceeded ${MAX_RESPONSE_BYTES} bytes`));
72	          }
73	        });
74	        res.on("end", () => {
75	          const status = res.statusCode ?? 500;
76	          if (status < 200 || status >= 300) {
77	            reject(new Error(`${label} failed (${config.name}): HTTP ${status} — ${raw.trim()}`));
78	            return;
79	          }
80	          try {
81	            resolve(JSON.parse(raw) as T);
82	          } catch (err) {
83	            reject(new Error(`${label} failed (${config.name}): invalid JSON response: ${err instanceof Error ? err.message : String(err)}`));
84	          }
85	        });
86	        res.on("error", reject);
87	      },
88	    );
89	
90	    req.setTimeout(timeoutMs, () => {
91	      req.destroy(new Error("__NAS_TIMEOUT__"));
92	    });
93	    req.on("error", reject);
94	    req.write(payload);
95	    req.end();
96	  }).catch((err) => {
97	    throw normalizeRequestError(err, `${label} (${config.name})`, timeoutMs);
98	  });
99	}
