101	/** Returns NAS configs matching the target. "both" returns all configured NASes. */
102	export function getNasConfigs(target: string): NasConfig[] {
103	  const configs: NasConfig[] = [];
104	
105	  const nas1 = buildConfig(
106	    process.env.NAS_EDGE1_NAME ?? "edgesynology1",
107	    process.env.NAS_EDGE1_API_URL,
108	    process.env.NAS_EDGE1_API_SECRET,
109	    process.env.NAS_EDGE1_API_SIGNING_KEY,
110	  );
111	  const nas2 = buildConfig(
112	    process.env.NAS_EDGE2_NAME ?? "edgesynology2",
113	    process.env.NAS_EDGE2_API_URL,
114	    process.env.NAS_EDGE2_API_SECRET,
115	    process.env.NAS_EDGE2_API_SIGNING_KEY,
116	  );
117	
118	  if (nas1) configs.push(nas1);
119	  if (nas2) configs.push(nas2);
120	
121	  if (target === "both") return configs;
122	  const match = configs.find((c) => c.name === target);
123	  return match ? [match] : [];
124	}
125	
126	function buildConfig(
127	  name: string,
128	  url: string | undefined,
129	  apiSecret: string | undefined,
130	  approvalSigningKey: string | undefined,
131	): NasConfig | null {
132	  if (!url || !apiSecret || !approvalSigningKey) return null;
133	  return { name, url, apiSecret, approvalSigningKey };
134	}
135	
136	/**
137	 * Builds an HMAC-signed approval token for tier 2/3 commands.
138	 * Matches the token format expected by the NAS API validator.
139	 */
140	export function buildApprovalToken(config: NasConfig, command: string, tier: number): string {
141	  const expiresAt = new Date(Date.now() + 15 * 60_000).toISOString();
142	  const signature = createHmac("sha256", config.approvalSigningKey)
143	    .update(`${command}\n${expiresAt}`)
144	    .digest("hex");
145	  return Buffer.from(
146	    JSON.stringify({ command, tier, expires_at: expiresAt, signature }),
147	  ).toString("base64url");
148	}
149	
